  "<!doctype html><html dir=\"rtl\" lang=\"ar\"><head><meta charset=\"utf-8\"/>\n      <title>الربح الحقيقي — ${labelOf[range]}</title>\n      <style>\n        body{font-family:Cairo,system-ui,sans-serif;padding:24px;color:#111}\n        h1{margin:0 0 12px}\n        table{width:100%;border-collapse:collapse;font-size:14px}\n        td{padding:8px 10px;border-bottom:1px solid #eee}\n        .total{font-weight:bold;font-size:18px;background:#fafafa}\n        .pos{color:#16a34a} .neg{color:#dc2626}\n      </style></head><body>\n      <h1>تقرير الربح الحقيقي — ${labelOf[range]}</h1>\n      <table>\n        <tr><td>إجمالي الإيرادات</td><td style=\"text-align:left\" class=\"pos\">+ ${fmt(data.revenue)} دج</td></tr>\n        <tr><td>مصاريف التشغيل</td><td style=\"text-align:left\" class=\"neg\">- ${fmt(data.operatingExpenses)} دج</td></tr>\n        <tr><td>مشتريات الموردين</td><td style=\"text-align:left\" class=\"neg\">- ${fmt(data.purchases)} دج</td></tr>\n        <tr><td>رواتب الموظفين</td><td style=\"text-align:left\" class=\"neg\">- ${fmt(data.salaries)} دج</td></tr>\n        <tr><td>تكلفة الهدر</td><td style=\"text-align:left\" class=\"neg\">- ${fmt(data.waste)} دج</td></tr>\n        <tr class=\"total\"><td>${net >= 0 ? \"الربح الصافي\" : \"الخسارة الصافية\"}</td>\n          <td style=\"text-align:left\" class=\"${net >= 0 ? \"pos\" : \"neg\"}\">${fmt(net)} دج</td></tr>\n      </table>\n      <script>window.onload=()=>setTimeout(()=>window.print(),300)</script>\n      </body></html>": { fr: "<!doctype html><html dir=\"rtl\" lang=\"ar\"><head><meta charset=\"utf-8\"/>\n      <title>Bénéfice Réel — ${labelOf[range]}</title>\n      <style>\n        body{font-family:Cairo,system-ui,sans-serif;padding:24px;color:#111}\n        h1{margin:0 0 12px}\n        table{width:100%;border-collapse:collapse;font-size:14px}\n        td{padding:8px 10px;border-bottom:1px solid #eee}\n        .total{font-weight:bold;font-size:18px;background:#fafafa}\n        .pos{color:#16a34a} .neg{color:#dc2626}\n      </style></head><body>\n      <h1>Rapport de Bénéfice Réel — ${labelOf[range]}</h1>\n      <table>\n        <tr><td>Revenus Totaux</td><td style=\"text-align:left\" class=\"pos\">+ ${fmt(data.revenue)} دج</td></tr>\n        <tr><td>Dépenses d'exploitation</td><td style=\"text-align:left\" class=\"neg\">- ${fmt(data.operatingExpenses)} دج</td></tr>\n        <tr><td>Achats Fournisseurs</td><td style=\"text-align:left\" class=\"neg\">- ${fmt(data.purchases)} دج</td></tr>\n        <tr><td>Salaires des Employés</td><td style=\"text-align:left\" class=\"neg\">- ${fmt(data.salaries)} دج</td></tr>\n        <tr><td>Coût du Gaspillage</td><td style=\"text-align:left\" class=\"neg\">- ${fmt(data.waste)} دج</td></tr>\n        <tr class=\"total\"><td>${net >= 0 ? \"Bénéfice Net\" : \"Perte Nette\"}</td>\n          <td style=\"text-align:left\" class=\"${net >= 0 ? \"pos\" : \"neg\"}\">${fmt(net)} دج</td></tr>\n      </table>\n      <script>window.onload=()=>setTimeout(()=>window.print(),300)</script>\n      </body></html>", en: "<!doctype html><html dir=\"rtl\" lang=\"ar\"><head><meta charset=\"utf-8\"/>\n      <title>True Profit — ${labelOf[range]}</title>\n      <style>\n        body{font-family:Cairo,system-ui,sans-serif;padding:24px;color:#111}\n        h1{margin:0 0 12px}\n        table{width:100%;border-collapse:collapse;font-size:14px}\n        td{padding:8px 10px;border-bottom:1px solid #eee}\n        .total{font-weight:bold;font-size:18px;background:#fafafa}\n        .pos{color:#16a34a} .neg{color:#dc2626}\n      </style></head><body>\n      <h1>True Profit Report — ${labelOf[range]}</h1>\n      <table>\n        <tr><td>Total Revenue</td><td style=\"text-align:left\" class=\"pos\">+ ${fmt(data.revenue)} دج</td></tr>\n        <tr><td>Operating Expenses</td><td style=\"text-align:left\" class=\"neg\">- ${fmt(data.operatingExpenses)} دج</td></tr>\n        <tr><td>Supplier Purchases</td><td style=\"text-align:left\" class=\"neg\">- ${fmt(data.purchases)} دج</td></tr>\n        <tr><td>Employee Salaries</td><td style=\"text-align:left\" class=\"neg\">- ${fmt(data.salaries)} دج</td></tr>\n        <tr><td>Cost of Waste</td><td style=\"text-align:left\" class=\"neg\">- ${fmt(data.waste)} دج</td></tr>\n        <tr class=\"total\"><td>${net >= 0 ? \"Net Profit\" : \"Net Loss\"}</td>\n          <td style=\"text-align:left\" class=\"${net >= 0 ? \"pos\" : \"neg\"}\">${fmt(net)} دج</td></tr>\n      </table>\n      <script>window.onload=()=>setTimeout(()=>window.print(),300)</script>\n      </body></html>" },
