export function tx(ar: string): string {
  const lng = (i18n.language || "ar").split("-")[0];
  if (lng === "ar") return ar;
  const entry = dict[ar];
  if (!entry) return ar;
  if (lng === "fr") return entry.fr;
  if (lng === "en") return entry.en;
  return ar;
}
